INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4325, 8012, 'tt0113161', NULL, 'Get Shorty', 'Get Shorty', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/r82SdPhg4fnIcLt0ogIjQxqjdcO.jpg', 'https://image.tmdb.org/t/p/original/wiZT8DVmAZNwmqd8G3QjWZ1mpLB.jpg', 'Chili Palmer is a Miami mobster who gets sent to L.A. to collect a bad debt from Harry Zimm, a Hollywood producer who specializes in cheesy horror films. When Chili meets Harry''s leading lady, the romantic sparks fly. After pitching his own life story as a movie idea, Chili learns that being a mobster and being a Hollywood producer really aren''t all that different.', NULL, NULL, 1.6253, 6.5, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
