INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4327, 10024, 'tt1078588', NULL, 'My Sister''s Keeper', 'My Sister''s Keeper', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/atRGqnG7pe0hZP97RWDLrT2hRGZ.jpg', 'https://image.tmdb.org/t/p/original/zpVMWiNJgcwHB0zIMGjXQMnSKPZ.jpg', 'Sara and Brian live an idyllic life with their young son and daughter. But their family is rocked by sudden, heartbreaking news that forces them to make a difficult and unorthodox choice in order to save their baby girl''s life. The parents'' desperate decision raises both ethical and moral questions and rips away at the foundation of their relationship. Their actions ultimately set off a court case that threatens to tear the family apart, while revealing surprising truths that challenge everyone''s perceptions of love and loyalty and give new meaning to the definition of healing.', NULL, NULL, 6.2431, 7.37, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4328, 397722, 'tt5649108', NULL, 'Thoroughbreds', 'Thoroughbreds', 'movie', 2018, 'https://image.tmdb.org/t/p/w500/dBhskn3zQZu1DKy1ZjjmJRxJUxm.jpg', 'https://image.tmdb.org/t/p/original/99Rd26ceIhonpOP5JoqcXYqnkD.jpg', 'Lily and Amanda, two high school students living in suburban Connecticut, rekindle their unlikely friendship after years of drifting apart. Together, they devise a plan to kill Lily''s abusive stepfather by hiring a lowlife drug dealer.', NULL, NULL, 2.4229, 6.429, 0, 6.33333333333333303e+00, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4329, 577, 'tt0114681', NULL, 'To Die For', 'To Die For', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/whz4bwvqE1OmQHIyqHdZD8jU9CO.jpg', 'https://image.tmdb.org/t/p/original/7LNkP4ofj5pPgPeyEXC5z3U4y8a.jpg', 'Suzanne Stone wants to be a world-famous news anchor and she is willing to do anything to get what she wants. What she lacks in intelligence, she makes up for in cold determination and diabolical wiles. As she pursues her goal with relentless focus, she is forced to destroy anything and anyone that may stand in her way, regardless of the ultimate cost or means necessary.', NULL, NULL, 2.7216, 6.583, 0, 7.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4330, 402, 'tt0103772', NULL, 'Basic Instinct', 'Basic Instinct', 'movie', 1992, 'https://image.tmdb.org/t/p/w500/76Ts0yoHk8kVQj9MMnoMixhRWoh.jpg', 'https://image.tmdb.org/t/p/original/7FRraud59N3s10bbf9bfYjvwx3v.jpg', 'Catherine, a novelist with an insatiable sexual appetite, becomes a prime suspect when her boyfriend is brutally murdered -- a crime she had described in her latest story.', NULL, NULL, 12.3561, 6.947, 0, 7.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4331, 6145, 'tt0488120', NULL, 'Fracture', 'Fracture', 'movie', 2007, 'https://image.tmdb.org/t/p/w500/qNen8x5gaikjIg9CFihgxYcJwQe.jpg', 'https://image.tmdb.org/t/p/original/mujUrk2diGe5vRCb3kdpHZeobRs.jpg', 'A husband is on trial for the attempted murder of his wife, in what is seemingly an open/shut case for the ambitious district attorney trying to put him away. However, there are surprises for both around every corner, and, as a suspenseful game of cat-and-mouse is played out, each must manipulate and outwit the other.', NULL, NULL, 4.9665, 7.262, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4332, 2768, 'tt0080365', NULL, 'American Gigolo', 'American Gigolo', 'movie', 1980, 'https://image.tmdb.org/t/p/w500/igXGCwti23PHOjLKQX6eGIGzQiJ.jpg', 'https://image.tmdb.org/t/p/original/tnbEY8Kn0mPyMfkxONYePWP5RUa.jpg', 'Julian makes a lucrative living as an escort to older women in the Los Angeles area. He begins a relationship with Michelle, a local politician''s wife, without expecting any pay. One of his clients is murdered and Detective Sunday begins pumping him for details on his different clients, something he is reluctant to do considering the nature of his work. Julian begins to suspect he''s being framed. Meanwhile Michelle begins to fall in love with him.', NULL, NULL, 2.7676, 6.2, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4333, 14290, 'tt0280477', NULL, 'Better Luck Tomorrow', 'Better Luck Tomorrow', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/alJULQQnuiYXjgVmj2EYgwXOcIn.jpg', 'https://image.tmdb.org/t/p/original/y0ulvcDrRtOOpI485sLi8q1kEr2.jpg', 'A group of over-achieving Asian-American high school seniors enjoy a power trip when they dip into extra-curricular criminal activities.', NULL, NULL, 0.9931, 6.226, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4334, 90, 'tt0086960', NULL, 'Beverly Hills Cop', 'Beverly Hills Cop', 'movie', 1984, 'https://image.tmdb.org/t/p/w500/eBJEvKkhQ0tUt1dBAcTEYW6kCle.jpg', 'https://image.tmdb.org/t/p/original/p256RduW9wMC3uhGJTerywmGiiX.jpg', 'Fast-talking, quick-thinking Detroit street cop Axel Foley has bent more than a few rules and regs in his time, but when his best friend is murdered, he heads to sunny Beverly Hills to work the case like only he can.', NULL, NULL, 4.4076, 7.211, 0, 9.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4335, 96, 'tt0092644', NULL, 'Beverly Hills Cop II', 'Beverly Hills Cop II', 'movie', 1987, 'https://image.tmdb.org/t/p/w500/egDakU8O5yUwpUJP9IMAUVtIDll.jpg', 'https://image.tmdb.org/t/p/original/bIA65PCRtIQfBvIoKohJbtOPl3M.jpg', 'Axel Foley returns to the land of sunshine and palm trees to investigate the near-fatal shooting of police Captain Andrew Bogomil. With the help of Sgt. Taggart and Det. Rosewood, they soon uncover that the shooting is associated with a series of "alphabet" robberies masterminded by a heartless weapons kingpin—and the chase is on.', NULL, NULL, 3.2958, 6.536, 0, 9.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4336, 9702, 'tt0106469', NULL, 'Bound by Honor', 'Bound by Honor', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/gvP6R6juhe2IpCG7QGDgjyUvm0g.jpg', 'https://image.tmdb.org/t/p/original/9xjUZjuYyehv2qnqMH0oR9nSTft.jpg', 'Based on the true life experiences of poet Jimmy Santiago Baca, the film focuses on half-brothers Paco and Cruz, and their bi-racial cousin Miklo. It opens in 1972, as the three are members of an East L.A. gang known as the "Vatos Locos", and the story focuses on how a violent crime and the influence of narcotics alter their lives. Miklo is incarcerated and sent to San Quentin, where he makes a "home" for himself. Cruz becomes an exceptional artist, but a heroin addiction overcomes him with tragic results. Paco becomes a cop and an enemy to his "carnal", Miklo.', NULL, NULL, 7.3143, 8.196, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
