INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4359, 129418, 'tt1740725', NULL, 'Bigfoot: The Lost Coast Tapes', 'Bigfoot: The Lost Coast Tapes', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/esIg4M7lhgxtstGVPMvBXhctM1Y.jpg', 'https://image.tmdb.org/t/p/original/lvo5sNUv2IluVxLGTAA3oNZ29Z3.jpg', 'Sean Reynolds, a highly acclaimed investigative journalist (who strongly believed in paranormal phenomena), destroyed his career when the most watched episode of his reality show, based on paranormal phenomena, turned out to be a hoax. Sean saw a news report on a "Bigfoot Hunter" (Carl Drybeck) who claimed to possess the body of a dead Sasquatch. He believes Drybeck is a phony and decides to create a new show that reveals people''s paranormal claims as hoaxes. Sean assembles his old film crew and heads to Northern California''s "Lost Coast" to meet with and interview Drybeck. Obsessed, Sean is staking his comeback, his life and the lives of his documentary film crew on proving Drybeck''s claim to be a hoax.', NULL, NULL, 0.4719, 4.123, 0, 9.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
