INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4367, 464652, 'tt1580799', NULL, 'The Battle for L.A.', 'The Battle for L.A.', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/wZq0icD4y1XAIj1apDX0DAYp7Ws.jpg', NULL, 'Filmmaker Darren Doane ("42K") and a camera, hit the streets of L.A. in an almost guerilla-like fashion and interviews a number of DJs, rappers and dancers. Not only do they give their take on what hip-hop is, what it represents on a personal and social level, but he also attends what is termed "battles" between rappers. While such battles are known to get aggressive from time to time, it is often a way for people to blow off some steam, express themselves, strut their stuff and compete.', NULL, NULL, 0.042, 0.0, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
