INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4412, NULL, NULL, 216319, 'Assassin''s Creed Jade', 'Assassin''s Creed Jade', 'game', NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6zkr.jpg', NULL, 'Explore the path of Xia in Assassin’s Creed Codename Jade. Set in the third century BC during the time of one of the first unified empires in China, an unprecedented era of trade and cultural exchange between East and West is just beginning, but with this comes new challenges and threats lurking in the shadows.

From the Great Wall outside the empire’s borders to the imperial capital of Xianyang, journey through a world filled with ancient history and hidden dangers. Defend against the Xiongnu and work to dismantle conspiracies, taking on greater responsibilities, and facing new challenges.', 'https://www.igdb.com/games/assassins-creed-jade', '["Android", "iOS"]', NULL, NULL, 0, 6.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
