INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4418, NULL, NULL, 495, 'Metro 2033', 'Metro 2033', 'game', 2010, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rd6.jpg', NULL, 'Metro 2033 is a first-person shooter with survival horror elements, based on the Russian book of the same name by Dmitry Glukhovsky. Most of the game takes place underground, but several times Artyom will have to venture outside, into the perpetual nuclear winter. Game progression is fairly linear, though areas may be explored more thoroughly for items and ammunition. Setpieces include a few on-rails sequences, missions that involve defending a location from an onslaught of monsters, and others. A few stages can be completed in a stealthy fashion.', 'https://www.igdb.com/games/metro-2033', '["PC (Microsoft Windows)", "Xbox 360"]', NULL, NULL, 0, 8.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
