INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4420, 5470, 'tt0120604', NULL, 'Beowulf', 'Beowulf', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/ktX5naCHfERaoDVaCUOITPIFrFd.jpg', 'https://image.tmdb.org/t/p/original/9bdTdaqxT2ZEVGZwXsMvG7410cT.jpg', 'Beowulf is a wanderer who learns about a man-eating creature called Grendel, which comes in the night to devour warriors trapped at the Outpost. The Outpost is ruled by Hrothgar. He has a daughter, whose husband may have been murdered by the Outpost''s master of arms.', NULL, NULL, 1.6719, 4.386, 0, 6.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4421, 56715, 'tt0189192', NULL, 'Just Visiting', 'Just Visiting', 'movie', 2001, 'https://image.tmdb.org/t/p/w500/7KqzbefXjADSUE8j2ZsrudvAArY.jpg', 'https://image.tmdb.org/t/p/original/iRYEGEbpjbPQrxAXcIg9wlaO2xm.jpg', 'A knight and his valet are plagued by a witch, and to repair the damage they make use of the services of a wizard. However, something goes wrong and they are transported from the 12th century to the year 2000. There the knight meets some of his family and slowly learns what this new century is like. However, he still needs to get back to the 12th century to deal with the witch, so he starts looking for a wizard. Remake of  1993 French film Les Visiteurs (The Visitors).', NULL, NULL, 2.1754, 4.767, 0, 8.5, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4422, 11687, 'tt0108500', NULL, 'The Visitors', 'Les Visiteurs', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/hPCq0buG5PaXgKjzT2ktjrjlpbj.jpg', 'https://image.tmdb.org/t/p/original/t9N0AYD6j2d3dSPDdeOhhLmz1nb.jpg', 'After a wizard''s spell goes awry, 12th-century Gallic knight Godefroy de Papincourt, Count of Montmirail finds himself transported to 1993, along with his dimwitted servant, Jacquouille la Fripouille. Startled and perplexed by modern technology, the duo run amok, destroying cars and causing chaos until they meet Beatrice de Montmirail, an aristocratic descendant of the nobleman, who may be able to help them get back to 1123.', NULL, NULL, 2.7738, 7.127, 0, 6.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4423, 47450, 'tt3865236', NULL, 'Into the Badlands', 'Into the Badlands', 'tv', 2015, 'https://image.tmdb.org/t/p/w500/jtceMKMxHSriLFUGAUfqHsW7uCo.jpg', 'https://image.tmdb.org/t/p/original/1p9FUL7MKKOW0ZhsXkbpD3DVTy1.jpg', 'In a land controlled by feudal barons, a great warrior and a young boy embark on a journey across a dangerous land to find enlightenment. 

A genre-bending martial arts series very loosely based on the classic Chinese tale Journey to the West.', NULL, NULL, 9.0562, 7.619, 0, 7.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4424, 2059, 'tt0368891', NULL, 'National Treasure', 'National Treasure', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/pxL6E4GBOPUG6CdkO9cUQN5VMwI.jpg', 'https://image.tmdb.org/t/p/original/9EnZD3ZWjpJy4IPoQkqTzxvZrso.jpg', 'Modern treasure hunters, led by archaeologist Ben Gates, search for a chest of riches rumored to have been stashed away by George Washington, Thomas Jefferson and Benjamin Franklin during the Revolutionary War. The chest''s whereabouts may lie in secret clues embedded in the Constitution and the Declaration of Independence, and Gates is in a race to find the gold before his enemies do.', NULL, NULL, 6.2346, 6.654, 0, 6.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
