INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4426, 15767, 'tt0399102', NULL, 'Godzilla: Final Wars', 'ゴジラ ファイナルウォーズ', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/21lWA4YyYppVnwAPOiBkGrt2FGr.jpg', 'https://image.tmdb.org/t/p/original/irLLP6uZRB10P4bCGZMzlGB5p6c.jpg', 'Humanity finally rids themselves of Godzilla, imprisoning him in an icy tomb in the South Pole. All is peaceful until various monsters emerge to lay waste to Earth''s cities. Overwhelmed, humanity is seemingly saved by a race of benevolent aliens known as Xiliens. But not all is what it seems with these bizarre visitors. If humanity wishes to survive, they must reluctantly resurrect their most hated enemy, Godzilla.', NULL, NULL, 2.5859, 7.116, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
