INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4460, 2430, 'tt0408381', NULL, 'Doc Martin', 'Doc Martin', 'tv', 2004, 'https://image.tmdb.org/t/p/w500/zmd4ZpdXWnjKVrenqvYyYstOkwK.jpg', 'https://image.tmdb.org/t/p/original/g0LCSXvweUAMW8jB3O2ECMwDAua.jpg', 'Doc Martin is a British television comedy drama series starring Martin Clunes in the title role. It was created by Dominic Minghella after the character of Dr. Martin Bamford in the 2000 comedy film Saving Grace. The show is set in the fictional seaside village of Portwenn and filmed on location in the village of Port Isaac, Cornwall, England, with most interior scenes shot in a converted local barn. Five series aired between 2004 and 2011, together with a feature-length special that aired on Christmas Day 2006. Series 6 began airing on ITV on 2 September 2013.', NULL, NULL, 12.4413, 8.3, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
