INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4568, 337404, 'tt3228774', NULL, 'Cruella', 'Cruella', 'movie', 2021, 'https://image.tmdb.org/t/p/w500/hjS9mH8KvRiGHgjk6VUZH7OT0Ng.jpg', 'https://image.tmdb.org/t/p/original/6MKr3KgOLmzOP6MSuZERO41Lpkt.jpg', 'In 1970s London amidst the punk rock revolution, a young grifter named Estella is determined to make a name for herself with her designs. She befriends a pair of young thieves who appreciate her appetite for mischief, and together they are able to build a life for themselves on the London streets. One day, Estella’s flair for fashion catches the eye of the Baroness von Hellman, a fashion legend who is devastatingly chic and terrifyingly haute. But their relationship sets in motion a course of events and revelations that will cause Estella to embrace her wicked side and become the raucous, fashionable and revenge-bent Cruella.', NULL, NULL, 12.2384, 7.972, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4569, 705, 'tt0042192', NULL, 'All About Eve', 'All About Eve', 'movie', 1950, 'https://image.tmdb.org/t/p/w500/blBzZaatPWVuWpXEnPscMA4Xp6m.jpg', 'https://image.tmdb.org/t/p/original/zAL3LOswagN9onjN8DPcNFTqKuD.jpg', 'From the moment she glimpses her idol at the stage door, Eve Harrington is determined to take the reins of power away from the great actress Margo Channing. Eve maneuvers her way into Margo''s Broadway role, becomes a sensation and even causes turmoil in the lives of Margo''s director boyfriend, her playwright and his wife. Only the cynical drama critic sees through Eve, admiring her audacity and perfect pattern of deceit.', NULL, NULL, 2.6362, 8.072, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4570, 71912, 'tt5180504', NULL, 'The Witcher', 'The Witcher', 'tv', 2019, 'https://image.tmdb.org/t/p/w500/AoGsDM02UVt0npBA8OvpDcZbaMi.jpg', 'https://image.tmdb.org/t/p/original/foGkPxpw9h8zln81j63mix5B7m8.jpg', 'Geralt of Rivia, a mutated monster-hunter for hire, journeys toward his destiny in a turbulent world where people often prove more wicked than beasts.', NULL, NULL, 55.219, 7.906, 0, 3.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4571, 64915, 'tt2798948', NULL, 'Season of the Witch', 'Tími nornarinnar', 'tv', 2011, 'https://image.tmdb.org/t/p/w500/evhdceP8xItrwOlYsSmJspnELcg.jpg', 'https://image.tmdb.org/t/p/original/wDBVpE6FTYgqbqppvLbVu8Bn14p.jpg', 'A woman falls overboard during a rafting trip in Skagafjörður, hits her head on a rock and later dies without having gained consciousness. Her mother contacts Einar and tells him she was murdered. Einar finds this hard to believe but starts investigating anyway, more as as sop to the old lady, whom he likes, than on suspicion of finding anything suspicious. Shortly afterwards a charismatic young man disappears and Einar gets orders to write up a story about the investigation, while also covering a problem with politics and hooliganism in a village a few hour’s drive from Akureyri. His investigation leads to interesting facts about the young man, who was not all he seemed to be, and also about the dead woman’s husband. At the same time Einar finds himself embroiled in two separate family dramas with quite different outcomes.', NULL, NULL, 0.4134, 8.0, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4572, 63333, 'tt4179452', NULL, 'The Last Kingdom', 'The Last Kingdom', 'tv', 2015, 'https://image.tmdb.org/t/p/w500/8eJf0hxgIhE6QSxbtuNCekTddy1.jpg', 'https://image.tmdb.org/t/p/original/QbtctI8EzlhsyFDMUMyG3fli8B.jpg', 'A show of heroic deeds and epic battles with a thematic depth that embraces politics, religion, warfare, courage, love, loyalty and our universal search for identity. Combining real historical figures and events with fictional characters, it is the story of how a people combined their strength under one of the most iconic kings of history in order to reclaim their land for themselves and build a place they call home.', NULL, NULL, 37.162, 8.264, 0, 5.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4573, 1891, 'tt0384766', NULL, 'Rome', 'Rome', 'tv', 2005, 'https://image.tmdb.org/t/p/w500/1A1BwgWO3Sw379VEhR0vkTuE3XW.jpg', 'https://image.tmdb.org/t/p/original/b2fhZk0xB2TgMsDXT6goR28PoHX.jpg', 'A down-to-earth account of the lives of both illustrious and ordinary Romans set in the last days of the Roman Republic.', NULL, NULL, 16.5332, 8.2, 0, 4.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4574, 4616, 'tt0112230', NULL, 'Xena: Warrior Princess', 'Xena: Warrior Princess', 'tv', 1995, 'https://image.tmdb.org/t/p/w500/qjUn6GVZVDifLHB7bvVrgZsOfzE.jpg', 'https://image.tmdb.org/t/p/original/1V7WuDv5kmzwCCNd9CNQvOmqHdm.jpg', 'Xena is an infamous warrior on a quest to seek redemption for her past sins against the innocent. Accompanied by her comrade-in-arms Gabrielle, the campy couple use their formidable fighting skills to help those who are unable to defend themselves.', NULL, NULL, 37.4058, 7.564, 0, 2.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4575, 46296, 'tt1442449', NULL, 'Spartacus', 'Spartacus', 'tv', 2010, 'https://image.tmdb.org/t/p/w500/c2GKN4VHCj1dnjFMANRpGkCVBae.jpg', 'https://image.tmdb.org/t/p/original/zbfXS4o6UykeXsD8djFTyV7Cj4N.jpg', 'Torn from his homeland and the woman he loves, Spartacus is condemned to the brutal world of the arena where blood and death are primetime entertainment.', NULL, NULL, 49.1598, 8.034, 0, 4.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4576, 33958, 'tt1672189', NULL, 'Camelot', 'Camelot', 'tv', 2011, 'https://image.tmdb.org/t/p/w500/kT4yBlYjB0Cm6Qp9bwkjXrFPU1v.jpg', 'https://image.tmdb.org/t/p/original/iIsRu2x3gTLoH26DGs9gpvrvqPg.jpg', 'With King Uther''s sudden death, chaos threatens to engulf Britain. The sorcerer Merlin has visions of a dark future and installs young and impetuous Arthur, Uther''s unknown son and heir raised as a commoner, as the new king. The two install themselves in Castle Camelot with their allies, which include Arthur''s biological mother, his foster brother, and a quartet of loyal warriors. From Camelot, Arthur tries to build a new and better Britain, where people can live in peace.

Meanwhile, Arthur''s cold half-sister Morgan plots to take the crown from him. Banished by Uther, who was responsible for her mother''s murder to put Arthur''s mother on the throne, Morgan is responsible for Uther''s death and wants to rule as his successor. Aided by her loyal maid Vivian and the devious nun Sybil, Morgan takes up residence in Castle Pendragon, from where she schemes against Arthur.', NULL, NULL, 7.3033, 6.311, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4577, 7225, 'tt1199099', NULL, 'Merlin', 'Merlin', 'tv', 2008, 'https://image.tmdb.org/t/p/w500/8eR5Jg7CxsuCOEBU5wW0opObxpi.jpg', 'https://image.tmdb.org/t/p/original/2JcrP4gNhU3KMbdajoEi1OvDl1Y.jpg', 'The unlikely friendship between Merlin, a young man gifted with extraordinary magical powers, and Prince Arthur, heir to the crown of Camelot.', NULL, NULL, 23.3369, 7.827, 0, 2.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4578, 79224, 'tt2025526', NULL, 'War of the Arrows', '최종병기 활', 'movie', 2011, 'https://image.tmdb.org/t/p/w500/iOTRRHt9GNbUfQhV3MhMCznjrPI.jpg', 'https://image.tmdb.org/t/p/original/l9KInBleoVHFB2TXxChn6pjlDxz.jpg', 'After the death of their father, two siblings are raised by their father''s best friend. However, when one gets kidnapped just before her wedding, the other rises against the Manchus.', NULL, NULL, 2.1907, 7.198, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4579, 38543, 'tt1233301', NULL, 'Ironclad', 'Ironclad', 'movie', 2011, 'https://image.tmdb.org/t/p/w500/h7CP12wAThhw2WSOA1uIAqxg1fS.jpg', 'https://image.tmdb.org/t/p/original/rprg34i9MfIRAJdBcjAWaV7JXRe.jpg', 'In the year 1215, the rebel barons of England have forced their despised King John to put his royal seal on the Magna Carta, a seminal document that upheld the rights of free men. Yet within months of pledging himself to the great charter, the King reneged on his word and assembled a mercenary army on the south coast of England with the intention of bringing the barons and the country back under his tyrannical rule. Barring his way stood the mighty Rochester castle, a place that would become the symbol of the rebel''s momentous struggle for justice and freedom.', NULL, NULL, 2.5402, 6.15, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4580, 20662, 'tt0955308', NULL, 'Robin Hood', 'Robin Hood', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/kE4Wie1VVRGQbVSIsEnxmly3FqZ.jpg', 'https://image.tmdb.org/t/p/original/gxJnDz2W566PRdYKCaJrp1FpRRI.jpg', 'When soldier Robin happens upon the dying Robert of Loxley, he promises to return the man''s sword to his family in Nottingham. There, he assumes Robert''s identity; romances his widow, Marion; and draws the ire of the town''s sheriff and King John''s henchman, Godfrey.', NULL, NULL, 3.9091, 6.401, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4581, 88803, 'tt10233448', NULL, 'Vinland Saga', 'ヴィンランド・サガ', 'tv', 2019, 'https://image.tmdb.org/t/p/w500/vUHlpA5c1NXkds59reY3HMb4Abs.jpg', 'https://image.tmdb.org/t/p/original/pSLuy0OfN1QblifDVoEhAvst4et.jpg', 'For a thousand years, the Vikings have made quite a name and reputation for themselves as the strongest families with a thirst for violence. Thorfinn, the son of one of the Vikings'' greatest warriors, spends his boyhood in a battlefield enhancing his skills in his adventure to redeem his most-desired revenge after his father was murdered.', NULL, NULL, 8.146, 8.527, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4582, 4935, 'tt0118451', NULL, 'Roar', 'Roar', 'tv', 1997, 'https://image.tmdb.org/t/p/w500/3xJLEhpVEN7aLsqJchbhzGOpRLv.jpg', 'https://image.tmdb.org/t/p/original/lAVXFxcAbz2O1TinM8rLrKAnHnQ.jpg', 'Roar is an American television show that originally aired on the Fox network in July 1997. In the year AD 400, a young Irish man, Conor, sets out to rid his land of the invading Romans, but in order to accomplish this, he must unite the Celtic clans.', NULL, NULL, 3.2335, 6.407, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
