INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4588, 13284, 'tt0450982', NULL, 'Barbie: Fairytopia', 'Barbie: Fairytopia', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/a0VPQHpLNCWWmiXwjD7aJVRaH78.jpg', 'https://image.tmdb.org/t/p/original/fr4rvbtATRrM7cruiVlbD2EJM2C.jpg', 'Elina is a flower fairy who discovers that her home of Magic Meadow has been overcome by a horrible malady that is killing the flowers and making the fairies unable to fly. With the help of Bibble, a puffball and a giant butterfly named Hue she attempts to find Azura, a Guardian Fairy. She''s challenged along the way by the evil Laverna who wants to usurp the Enchantress, the ruler of Fairytopia.', NULL, NULL, 3.4242, 6.805, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4589, 340617, 'tt0432103', NULL, 'Strawberry Shortcake: Best Pets Yet', 'Strawberry Shortcake: Best Pets Yet', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/eb0BhLqlJWXL7Iyo0QmdScTuvC0.jpg', 'https://image.tmdb.org/t/p/original/wTXBfZ9a6YZZT99auARTFXMZ6YL.jpg', 'Join your "berry" special friend, Strawberry Shortcake, for more delightful fun! In "Here Comes Pupcake," Strawberry takes in a little lost dog named Pupcake, but her spoiled house cat, Custard, does everything to make the peppy puppy want to leave! Then, in "Peppermint''s Pet Peeve," sneaky Peppermint Fizz cheats so that her pet, Cola Chameleon, wins a pet competition, only to learn that no one has to "win" anything in order to be happy and have fun!', NULL, NULL, 0.1361, 8.333, 0, 9.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4590, 52272, 'tt1719009', NULL, 'Bratz: Pampered Petz', 'Bratz: Pampered Petz', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/lReDruiEnPedgf1q0WjVf88Dzv0.jpg', 'https://image.tmdb.org/t/p/original/u1PGYfIgut13rfwBLiQCw6JTCEj.jpg', 'When Lola, a friend of the Bratz Girlz, is faced with eviction for harboring animals that she has rescued, the Bratz must combine their brainpower and talent to save them. The result is a hot rhythm benefit concert staged with the intent to find homes for all of Lola''s adorable Petz. To assure their success, the Girlz accessorize and bling-out the Petz in true Bratz style.', NULL, NULL, 0.5626, 7.4, 0, 9.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4591, 111474, 'tt9165438', NULL, 'Gabby''s Dollhouse', 'Gabby''s Dollhouse', 'tv', 2021, 'https://image.tmdb.org/t/p/w500/lyLvpLsC2WzBFZm2cIEn3VgKwEf.jpg', 'https://image.tmdb.org/t/p/original/qR4tS0urUUaFh6mlRhVUkDZGN5j.jpg', 'This colorful series leads preschoolers room to room through a fantastical dollhouse of delightful mini-worlds and irresistible kitty characters.', NULL, NULL, 11.0769, 7.898, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4592, 1301421, 'tt32565993', NULL, 'The Sheep Detectives', 'The Sheep Detectives', 'movie', 2026, 'https://image.tmdb.org/t/p/w500/mGWOmj2jHFol3kOGNv1EhbSDDE1.jpg', 'https://image.tmdb.org/t/p/original/a8uQvrplTkhGJQog6GZ6CqF8An6.jpg', 'George Hardy is a shepherd who reads detective novels to his beloved sheep every night, assuming they can''t possibly understand. But when a mysterious incident disrupts life on the farm, the sheep realize they must become the detectives. As they follow the clues and investigate human suspects, they prove that even sheep can be brilliant crime-solvers.', NULL, NULL, 71.1986, 7.892, 0, 6.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4593, 9291, 'tt0398165', NULL, 'The Longest Yard', 'The Longest Yard', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/nbKcVBcxF96ARW2oKHqDYAcLdu.jpg', 'https://image.tmdb.org/t/p/original/dXrHngmLabax5J5a7XfXhwcoFuL.jpg', 'Disgraced pro football quarterback Paul Crewe lands in a Texas federal penitentiary, where manipulative Warden Hazen recruits him to advise the institution''s football team of prison guards. Crewe suggests a tune-up game which lands him quarterbacking a crew of inmates in a game against the guards. Aided by incarcerated ex-NFL coach and player Nate Scarborough, Crewe and his team must overcome not only the bloodthirstiness of the opposition, but also the corrupt warden trying to fix the game against them.', NULL, NULL, 5.8764, 6.7, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4594, 11008, 'tt0110443', NULL, 'Major Payne', 'Major Payne', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/kWHx5eq7PELkF3If7LrrhuBskRG.jpg', 'https://image.tmdb.org/t/p/original/4lNbhZcnrjG079TUkG1mIi2wen0.jpg', 'Major Benson Winifred Payne is being discharged from the Marines. Payne is a killin'' machine, but the wars of the world are no longer fought on the battlefield. A career Marine, he has no idea what to do as a civilian, so his commander finds him a job - commanding officer of a local school''s JROTC program, a bunch of ragtag losers with no hope.', NULL, NULL, 3.0654, 6.482, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4595, 398978, 'tt1302006', NULL, 'The Irishman', 'The Irishman', 'movie', 2019, 'https://image.tmdb.org/t/p/w500/mbm8k3GFhXS0ROd9AD1gqYbIFbM.jpg', 'https://image.tmdb.org/t/p/original/1RDto0tLo8Fhq7OcwgDaM7nECb7.jpg', 'Pennsylvania, 1956. Frank Sheeran, a war veteran of Irish origin who works as a truck driver, accidentally meets mobster Russell Bufalino. Once Frank becomes his trusted man, Bufalino sends him to Chicago with the task of helping Jimmy Hoffa, a powerful union leader related to organized crime, with whom Frank will maintain a close friendship for nearly twenty years.', NULL, NULL, 7.2988, 7.576, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4596, 608, 'tt0120912', NULL, 'Men in Black II', 'Men in Black II', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/enA22EPyzc2WQ1VVyY7zxresQQr.jpg', 'https://image.tmdb.org/t/p/original/o1l6OCqA3pYDZHIc5L1s7CEzCMv.jpg', 'Kay and Jay reunite to provide our best, last and only line of defense against a sinister seductress who levels the toughest challenge yet to the MIB''s untarnished mission statement – protecting Earth from the scum of the universe. It''s been four years since the alien-seeking agents averted an intergalactic disaster of epic proportions. Now it''s a race against the clock as Jay must convince Kay – who not only has absolutely no memory of his time spent with the MIB, but is also the only living person left with the expertise to save the galaxy – to reunite with the MIB before the earth submits to ultimate destruction.', NULL, NULL, 6.9671, 6.388, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
