INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4620, 804, 'tt0046250', NULL, 'Roman Holiday', 'Roman Holiday', 'movie', 1953, 'https://image.tmdb.org/t/p/w500/8lI9dmz1RH20FAqltkGelY1v4BE.jpg', 'https://image.tmdb.org/t/p/original/gzRISGjiDMj4xqYE9ES2KNIXxpo.jpg', 'Overwhelmed by her suffocating schedule, touring European princess Ann takes off for a night while in Rome. When a sedative she took from her doctor kicks in, however, she falls asleep on a park bench and is found by an American reporter, Joe Bradley, who takes her back to his apartment for safety. At work the next morning, Joe finds out Ann''s regal identity and bets his editor he can get exclusive interview with her, but romance soon gets in the way.', NULL, NULL, 5.0055, 7.9, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
