INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4622, 747687, 'tt10345782', NULL, 'The Catholic School', 'La scuola cattolica', 'movie', 2021, 'https://image.tmdb.org/t/p/w500/WTTXAtuyQY93oe1yetWYMGbO7K.jpg', 'https://image.tmdb.org/t/p/original/kYJNrQ5say16fewLCdOVGjNpsX9.jpg', 'Three well-off young men—former students at Rome’s prestigious all-boys Catholic high school San Leone Magno—brutally tortured, raped, and murdered two young women in 1975. The event, which came to be known as the Circeo massacre, shocked and captivated the country, exposing the violence and dark underbelly of the upper middle class at a moment when the traditional structures of family and religion were seen as under threat.', NULL, NULL, 1.233, 6.176, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
