INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4658, NULL, NULL, 26223, 'Quern: Undying Thoughts', 'Quern: Undying Thoughts', 'game', 2016, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1hbm.jpg', NULL, 'Quern is a first person puzzle adventure with captivating story and beautiful graphics. Quern refreshes the genre with flexible gameplay and reuseable puzzle mechanics. The visuals and the music combine traditional and modern elements providing a unique mood for the game.

One of the specialities of Quern is that the tasks to be solved are not managed as separate, individual and sequential units, but as a complex entity, amongst which the players may wander and experiment freely. Often a bad or seemingly irrational result may bring the player closer to the final solution, if those are reconsidered and thought over again later, in the possession of the knowledge gained during the game.', 'https://www.igdb.com/games/quern-undying-thoughts', '["Linux", "PC (Microsoft Windows)", "PlayStation 5", "Mac", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4659, NULL, NULL, 8983, 'Obduction', 'Obduction', 'game', 2016, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wod.jpg', NULL, 'From Cyan, the indie studio that brought you Myst and Riven comes a whole new adventure that will become your world.

The new worlds of Obduction reveal their secrets only as you explore, coax, and consider them. And as you bask in the otherworldly beauty and explore through the enigmatic landscapes, remember that the choices you make will have substantial consequences. This is your story now.', 'https://www.igdb.com/games/obduction', '["Windows Mixed Reality", "PlayStation 4", "PlayStation VR", "PC (Microsoft Windows)", "iOS", "SteamVR", "Mac", "Oculus Rift", "Xbox One"]', NULL, NULL, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
