INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4666, 658, 'tt0058150', NULL, 'Goldfinger', 'Goldfinger', 'movie', 1964, 'https://image.tmdb.org/t/p/w500/3zqmjujYSkgLSrdvvZ9VnDfaDRV.jpg', 'https://image.tmdb.org/t/p/original/f1Is9VLQZSRpeLMU7mIcj5aXclt.jpg', 'Special agent 007 comes face to face with one of the most notorious villains of all time, and now he must outwit and outgun the powerful tycoon to prevent him from cashing in on a devious scheme to raid Fort Knox -- and obliterate the world''s economy.', NULL, NULL, 5.0765, 7.361, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
