INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4668, 210, 'tt0057765', NULL, 'The Man from U.N.C.L.E.', 'The Man from U.N.C.L.E.', 'tv', 1964, 'https://image.tmdb.org/t/p/w500/a0nMOwNZXyJrMTPoaCzJJZeT0Yl.jpg', 'https://image.tmdb.org/t/p/original/rcKJYoqQxhjQfsKBb6CUbFMSoMh.jpg', 'Agents Napoleon Solo and Illya Kuryakin work for a secret intelligence service working under the auspices of the U.N.

Their immediate superior is Mr. Waverly.

Together  they operate out of a secret base beneath the streets of New York City, and accesses through several cover business such as Del Floria''s Tailor Shop and the Masque Club.

This secret intelligence service is called U.N.C.L.E.

United Network Command for Law and Enforcement.', NULL, NULL, 8.6964, 7.1, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4669, 26685, 'tt0058212', NULL, 'How to Murder Your Wife', 'How to Murder Your Wife', 'movie', 1965, 'https://image.tmdb.org/t/p/w500/1lwxAeN3OGXkoPH9DzZrRtA7XK0.jpg', 'https://image.tmdb.org/t/p/original/3BlLlwc1dLWLpgFQG9l5Fzzl5Xg.jpg', 'Stanley Ford leads an idyllic bachelor life. He is a nationally syndicated cartoonist whose Bash Brannigan series provides him with a luxury townhouse and a full-time valet, Charles. When he wakes up the morning after the night before - he had attended a friend''s stag party - he finds that he is married to the very beautiful woman who popped out of the cake - and who doesn''t speak a word of English. Despite his initial protestations, he comes to like married life and even changes his cartoon character from a super spy to a somewhat harried husband.', NULL, NULL, 1.1892, 6.316, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4670, 85271, 'tt9140560', NULL, 'WandaVision', 'WandaVision', 'tv', 2021, 'https://image.tmdb.org/t/p/w500/ijWWwINc8h71NQ8j1LTJMFSj5wr.jpg', 'https://image.tmdb.org/t/p/original/lOr9NKxh4vMweufMOUDJjJhCRHW.jpg', 'Wanda Maximoff and Vision—two super-powered beings living idealized suburban lives—begin to suspect that everything is not as it seems.', NULL, NULL, 17.423, 8.186, 0, 9.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4671, 43745, 'tt0059794', NULL, 'That Funny Feeling', 'That Funny Feeling', 'movie', 1965, 'https://image.tmdb.org/t/p/w500/x2Wt8tpk9o9KHhZM1QBXvMbaqgT.jpg', 'https://image.tmdb.org/t/p/original/f9kXXdeaWu6g1IO7SlX2IW9VeQy.jpg', 'Joan Howell, a young and pretty maid-for-hire, meets and begins dating wealthy New York City businessman Tom Milford. Embarrassed about bringing him back to her tiny apartment that she shares with her roommate Audrey, Joan brings Tom over to a fancy apartment that she cleans on a daily basis not knowing that it''s his place. Tom plays along with the charade despite not knowing who Joan really is, while she tries to tidy up Tom''s place not knowing who he really is.', NULL, NULL, 0.7311, 6.283, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4672, 882406, 'tt13561390', NULL, 'The Bells are Ringing for Ahuva Ozeri', 'אהובה עוזרי צלצולי פעמונים', 'movie', 2020, 'https://image.tmdb.org/t/p/w500/A0JcI8hCv5zVVPPFTGF9zmjIzGs.jpg', 'https://image.tmdb.org/t/p/original/7Gk8r1YnoRd5v1h84x2eV4kpVBM.jpg', 'In 1999, after a 23-year absence, gifted musician Ahuva Ozeri is planning a comeback. She''s recording a new album - The Bells are Ringing.  Ahuva, considered the queen of the Middle Eastern music, sits at home and makes a living as a cook at a meat restaurant.  She hopes to break out again with the new album. But at the end of the recording, she is diagnosed with throat cancer and undergoes surgery where her vocal cords are cut. She loses her voice forever, but the album is very successful. It managed to cross audiences and becomes a consensus.  This film is based on rare never before-seen materials, sketching her life''s course.', NULL, NULL, 0.5826, 7.0, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4673, 46081, 'tt0056093', NULL, 'If a Man Answers', 'If a Man Answers', 'movie', 1962, 'https://image.tmdb.org/t/p/w500/7wupF3mY2RWFHGO0zT0ctCFo2GL.jpg', 'https://image.tmdb.org/t/p/original/9uYktPaKu6hRPGfgd7OAHpgGeBs.jpg', 'Rich socialite Chantal marries photographer Eugene and everything seems blissful until her envious friend attempts to break them up. In desperation, she turns to her mother, but the advice she receives may do more harm than good.', NULL, NULL, 0.5877, 6.1, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
