INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4684, 936, 'tt0057413', NULL, 'The Pink Panther', 'The Pink Panther', 'movie', 1963, 'https://image.tmdb.org/t/p/w500/aCjJ0sKayks2uL7MJBzdp2i67NI.jpg', 'https://image.tmdb.org/t/p/original/iruYVg36Jj8ol4z5owDHOEZH0nt.jpg', 'The trademark of The Phantom, a renowned jewel thief, is a glove left at the scene of the crime. Inspector Clouseau, an expert on The Phantom''s exploits, feels sure that he knows where The Phantom will strike next and leaves Paris for the Tyrolean Alps, where the famous Lugashi jewel ''The Pink Panther'' is going to be. However, he does not know who The Phantom really is, or for that matter who anyone else really is...', NULL, NULL, 3.2561, 6.844, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
