INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4686, 76018, 'tt0061748', NULL, 'The Happening', 'The Happening', 'movie', 1967, 'https://image.tmdb.org/t/p/w500/wVsMBspODOOXMYhzWrP3dAgPkVV.jpg', 'https://image.tmdb.org/t/p/original/m0SwOSg8w5wVX8CoUsDfeVvowKE.jpg', 'A group of young drifters kidnap wealthy businessman Roc Delmonico just for kicks. They keep him captive, demanding a ransom for his safe release. However there is no one - wife, Mafia associates or mother - willing to part with the $200,000 ransom. Demonico is dismayed that no one appears unduly concerned about his fate and joins forces with the kidnappers to plot his revenge, blackmailing his once nearest and dearest into parting with $3,000,000 in hush money.', NULL, NULL, 0.5277, 6.25, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
