INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4726, 7520, 'tt0094889', NULL, 'Cocktail', 'Cocktail', 'movie', 1988, 'https://image.tmdb.org/t/p/w500/jFRhEPhtsln9tDwzMdZN3OlhUob.jpg', 'https://image.tmdb.org/t/p/original/knYXryj3073w9fBMD5Xatk0ECiS.jpg', 'After being discharged from the Army, Brian Flanagan moves back to Queens and takes a job in a bar run by Doug Coughlin, who teaches Brian the fine art of bar-tending. Brian quickly becomes a patron favorite with his flashy drink-mixing style, and Brian adopts his mentor''s cynical philosophy on life and goes for the money.', NULL, NULL, 3.2334, 6.117, 0, 5.5, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
