INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4728, NULL, NULL, 1528, 'Jak and Daxter: The Precursor Legacy', 'Jak and Daxter: The Precursor Legacy', 'game', 2001, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w7q.jpg', NULL, 'Jak and Daxter: The Precursor Legacy is a 2001 platform video game developed by Naughty Dog and published by Sony Computer Entertainment for the Sony PlayStation 2 on December 4, 2001, as the first game of the Jak and Daxter series. The game follows the protagonist, a young teenager named Jak, as he tries to help his friend Daxter after he is transformed into an "ottsel", a fictional hybrid of an otter and a weasel.

The game offers a large range of missions, collectables and objectives, often in the form of minigames, which provide a variety of gameplay experiences, as well as puzzles and platforming stages, which are completed by the player to proceed with the story.', 'https://www.igdb.com/games/jak-and-daxter-the-precursor-legacy', '["PlayStation 4", "PlayStation 2"]', NULL, NULL, 0, 2.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4729, 451048, 'tt0870154', NULL, 'Jungle Cruise', 'Jungle Cruise', 'movie', 2021, 'https://image.tmdb.org/t/p/w500/yKy9ELL8CON5sqDg4yIvBb5LTZL.jpg', 'https://image.tmdb.org/t/p/original/7WJjFviFBffEJvkAms4uWwbcVUk.jpg', 'Dr. Lily Houghton enlists the aid of wisecracking skipper Frank Wolff to take her down the Amazon in his dilapidated boat. Together, they search for an ancient tree that holds the power to heal – a discovery that will change the future of medicine.', NULL, NULL, 6.0215, 7.282, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4730, 363, 'tt0310482', NULL, 'Legends of the Hidden Temple', 'Legends of the Hidden Temple', 'tv', 1993, 'https://image.tmdb.org/t/p/w500/jsUpyxfYgatd4UKZKfS6WZlkEhI.jpg', 'https://image.tmdb.org/t/p/original/83cizoNCw008s7IO6MtdnPq0xyl.jpg', 'In a Temple filled with lost treasures and protected by mysterious Mayan temple guards, six teams of two children compete to retrieve one of the historical artifacts in the Temple by performing physical stunts and answering questions based on history, mythology, and geography. After three elimination rounds, only one team remains, who then earns the right to go through the Temple to retrieve the artifact within three minutes and win a grand prize.', NULL, NULL, 7.4603, 7.483, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
