INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4733, 3850, 'tt0101169', NULL, 'The Pirates of Dark Water', 'The Pirates of Dark Water', 'tv', 1991, 'https://image.tmdb.org/t/p/w500/zCmCpZy2kmpna4C2OgvWozXGjOX.jpg', 'https://image.tmdb.org/t/p/original/aaDQsn7h5rlJ47b52jb8QKOE35r.jpg', 'When Ren, a young son of a lighthouse keeper, rescues a stranger foundering in the rocks near his home, he learns the man was an aide to his true father, a great King. Ren is given a magic compass crystal that guides him to a dragon who shows him that the only way to claim his heritage is to find the Thirteen Treasures of Rule. Unfortunately, a pirate ship captained by the evil Bloth is also aware of this treasure and is relentlessly pursuing Ren for it. On his side, Ren soon acquires companions like Ioz the Pirate, Tula the Eco-Mage, and Niddler the Monkey-Bird, who help him in his quest. That quest becomes all the more urgent when Ren learns that the Dark Water, a carnivorous form of water that consumes anything it snares, threatens to envelope and destroy his world and only the treasures he seeks can stop it.', NULL, NULL, 2.4745, 7.6, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
