INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4828, 121826, 'tt1441951', NULL, 'Quartet', 'Quartet', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/lDg2DfB5MuEoUeRFQqzBFVoWGep.jpg', 'https://image.tmdb.org/t/p/original/rsGYoSu8MNGabCMAnZIzzEHzIFd.jpg', 'Cissy, Reggie, and Wilf are in a home for retired musicians. Every year, there is a concert to celebrate Composer Giuseppe Verdi''s birthday and they take part. Jean, who used to be married to Reggie, arrives at the home and disrupts their equilibrium. She still acts like a diva, but she refuses to sing. Still, the show must go on, and it does.', NULL, NULL, 1.5664, 6.491, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
