INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4830, 8618, 'tt0464049', NULL, 'The History Boys', 'The History Boys', 'movie', 2006, 'https://image.tmdb.org/t/p/w500/klybhTU75GUcQbzdVXUhsZgq1EV.jpg', 'https://image.tmdb.org/t/p/original/A159OAi9EAU9v4l3sfMhpMqSK5v.jpg', 'The story of an unruly class of bright, funny history students at a Yorkshire grammar school in pursuit of an undergraduate place at Oxford or Cambridge. Bounced between their maverick English master, a young and shrewd teacher hired to up their test scores, a grossly out-numbered history teacher, and a headmaster obsessed with results, the boys attempt to pass.', NULL, NULL, 0.9924, 6.634, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4831, 11318, 'tt0110428', NULL, 'The Madness of King George', 'The Madness of King George', 'movie', 1994, 'https://image.tmdb.org/t/p/w500/1dTSY023ZyBbgVSKDRuA6JLGSnZ.jpg', 'https://image.tmdb.org/t/p/original/2Rf6jQMHGDZpzoeoNdBLbCyRCK7.jpg', 'Aging King George III of England is exhibiting signs of madness, a problem little understood in 1788. As the monarch alternates between bouts of confusion and near-violent outbursts of temper, his hapless doctors attempt the ineffectual cures of the day. Meanwhile, Queen Charlotte and Prime Minister William Pitt the Younger attempt to prevent the king''s political enemies, led by the Prince of Wales, from usurping the throne.', NULL, NULL, 1.7586, 6.799, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
