INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4854, 4610, 'tt0493093', NULL, 'Hannah Montana', 'Hannah Montana', 'tv', 2006, 'https://image.tmdb.org/t/p/w500/sRqLl0SHA4diTL8zvUTgBw6DQeM.jpg', 'https://image.tmdb.org/t/p/original/r7tiRgwCz4orOoYZIdbRdIGkfU3.jpg', 'At home and school, she''s Miley Stewart, a typical teenager, but when the lights go down and the curtain goes up, she emerges as the glamorous and talented Hannah Montana. Having the "Best of Both Worlds" is a complicated proposition, and keeping her identity under wraps leads Miley and her friends into some hilarious capers as she tries to balance her normal life with her rock star persona.', NULL, NULL, 23.2549, 7.12, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
