INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4856, 616584, 'tt10521814', NULL, 'K-12', 'K-12', 'movie', 2019, 'https://image.tmdb.org/t/p/w500/nVi0yBBPj5Z96JgGWVIg94kv7bR.jpg', 'https://image.tmdb.org/t/p/original/nXJrXFGK0pcGcEhvMOVZwVZlhXh.jpg', 'Cry Baby, a strong and sensitive girl, is sent off to a disturbing sleepaway school that’s hidden underneath a grandiose façade. Luckily, she has a sweet and unapologetic best friend who sticks up for her when she gets bullied by the other students whose brains are under control by the Principal and his wicked staff. With the help of the magical friends they meet along the way, as well as an Angelic Spirit Guide, they are able to gain the strength they need to fight off the school’s belligerent patriarchal conditioning.', NULL, NULL, 1.0199, 7.8, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4857, 433448, 'tt5039578', NULL, 'The Year of Spectacular Men', 'The Year of Spectacular Men', 'movie', 2018, 'https://image.tmdb.org/t/p/w500/kOIfl8eBQxqMkFjERyno7EFYCdj.jpg', 'https://image.tmdb.org/t/p/original/wfgzvM1Y94cEZk424eleze4Ruvw.jpg', 'In the year after graduating college, Izzy struggles to navigate the seemingly incessant failures of adulthood, the reality of a substandard dating pool and a debilitating fear of top-sheets, all in between X-Files marathons. Comically unsuccessful in love over the course the year, including five half-hearted relationships with astoundingly self-centered men, Izzy resigns herself to the support of her mother and sister, who are struggling with their own relationship problems. Seeing herself in them, Izzy gradually gains the confidence to be honest and vulnerable.', NULL, NULL, 0.8585, 5.575, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4858, 114, 'tt0100405', NULL, 'Pretty Woman', 'Pretty Woman', 'movie', 1990, 'https://image.tmdb.org/t/p/w500/hVHUfT801LQATGd26VPzhorIYza.jpg', 'https://image.tmdb.org/t/p/original/sGEqHTylawwS6hwKultk1mKUjdB.jpg', 'Vivian is a carefree, streetwise diamond in the rough when she meets sophisticated billionaire Edward in a chance encounter that turns into a week-long business arrangement. But Vivian''s energetic spirit challenges Edward''s no-nonsense approach to life, and soon they are teaching each other – and falling in love!', NULL, NULL, 8.8268, 7.4, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
