INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4861, 1287322, 'tt32323252', NULL, 'Christy', 'Christy', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/fDsxBOmBFL57QtKM9kTJ3AQU8lD.jpg', 'https://image.tmdb.org/t/p/original/lD8AzRc21Y19IstxSuNEpifoLKo.jpg', 'Christy Martin never imagined life beyond her small-town roots in West Virginia—until she discovered a knack for punching people. Fueled by grit, raw determination, and an unshakable desire to win, she charges into the world of boxing under the guidance of her trainer and manager-turned-husband, Jim. But while Christy flaunts a fiery persona in the ring, her toughest battles unfold outside it—confronting family, identity, and a relationship that just might become life-or-death.', NULL, NULL, 3.7538, 7.1, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
