INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4863, 903, 'tt0061512', NULL, 'Cool Hand Luke', 'Cool Hand Luke', 'movie', 1967, 'https://image.tmdb.org/t/p/w500/4ykzTiHKLamh3eZJ8orVICtU2Jp.jpg', 'https://image.tmdb.org/t/p/original/9TDi0FPOSAePfVLZXAUgFZhiMLf.jpg', 'When petty criminal Luke Jackson is sentenced to two years in a Florida prison farm, he doesn''t play by the rules of either the sadistic warden or the yard''s resident heavy, Dragline, who ends up admiring the new guy''s unbreakable will. Luke''s bravado, even in the face of repeated stints in the prison''s dreaded solitary confinement cell, "the box," make him a rebel hero to his fellow convicts and a thorn in the side of the prison officers.', NULL, NULL, 4.0445, 7.74, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
