INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4868, 10633, 'tt0061811', NULL, 'In the Heat of the Night', 'In the Heat of the Night', 'movie', 1967, 'https://image.tmdb.org/t/p/w500/qFpfALhprXmOAbA5upTNupZw8rq.jpg', 'https://image.tmdb.org/t/p/original/xY5sgU09cOsvEAgJZaYo2aOZEFi.jpg', 'African-American Philadelphia police detective Virgil Tibbs is arrested on suspicion of murder by Bill Gillespie, the racist police chief of tiny Sparta, Mississippi. After Tibbs proves not only his own innocence but that of another man, he joins forces with Gillespie to track down the real killer. Their investigation takes them through every social level of the town, with Tibbs making enemies as well as unlikely friends as he hunts for the truth.', NULL, NULL, 2.6312, 7.676, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
