INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4995, 11093, 'tt0315983', NULL, 'House of Sand and Fog', 'House of Sand and Fog', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/hLxSOukLfC4j5pNbdE7lqaw8KgL.jpg', 'https://image.tmdb.org/t/p/original/jZ9lWWCnV5gBRe29PpzEXNgf8i8.jpg', 'Behrani, an Iranian immigrant buys a California bungalow, thinking he can fix it up, sell it again, and make enough money to send his son to college. However, the house is the legal property of former drug addict Kathy. After losing the house in an unfair legal dispute with the county, she is left with nowhere to go. Wanting her house back, she hires a lawyer and befriends a police officer. Neither Kathy nor Behrani have broken the law, so they find themselves involved in a difficult moral dilemma.', NULL, NULL, 2.1934, 7.159, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4996, 149870, 'tt2013293', NULL, 'The Wind Rises', '風立ちぬ', 'movie', 2013, 'https://image.tmdb.org/t/p/w500/jfwSexzlIzaOgxP9A8bTA6t8YYb.jpg', 'https://image.tmdb.org/t/p/original/938lqhAQaO3hmLg44VbUR7OqlMs.jpg', 'A lifelong love of flight inspires Japanese aviation engineer Jiro Horikoshi, whose storied career includes the creation of the A-6M World War II fighter plane.', NULL, NULL, 4.3804, 7.786, 0, 10.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
