INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4998, 381063, 'tt5128826', NULL, 'The Alchemist Cookbook', 'The Alchemist Cookbook', 'movie', 2016, 'https://image.tmdb.org/t/p/w500/mD37S35Ewj6gJpJjfeBEX2qlzsR.jpg', 'https://image.tmdb.org/t/p/original/whcs30g1D0Xd5Fd2wV4Q0ELbAPH.jpg', 'Self-made chemist Sean, a recluse living in an old trailer in the woods, suffers from pill-popping delusions of fortune. When his manic attempts at cracking the ancient secret of alchemy go awry he unleashes something far more sinister and dangerous.', NULL, NULL, 0.5064, 5.169, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (4999, 11282, 'tt0366551', NULL, 'Harold & Kumar Go to White Castle', 'Harold & Kumar Go to White Castle', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/5vO7R4xYlDipTp8gzfRbWegO8eb.jpg', 'https://image.tmdb.org/t/p/original/dzloVSv0FGM8fs4L5w9yV60p0PT.jpg', 'Nerdy accountant Harold and his irrepressible friend, Kumar, get stoned watching television and find themselves utterly bewitched by a commercial for White Castle. Convinced there must be one nearby, the two set out on a late-night odyssey that takes them deep into New Jersey. Somehow, the boys manage to run afoul of rednecks, cops and even a car-stealing Neil Patrick Harris before getting anywhere near their beloved sliders.', NULL, NULL, 3.2298, 6.569, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5000, 8273, 'tt0328828', NULL, 'American Wedding', 'American Wedding', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/pCO3lJv2PzPkJty29APxCVSjyoE.jpg', 'https://image.tmdb.org/t/p/original/qW703anWHFXulRTKWOckAg9i70K.jpg', 'With high school a distant memory, Jim and Michelle are getting married — and in a hurry, since Jim''s grandmother is sick and wants to see him walk down the aisle — prompting Stifler to throw the ultimate bachelor party. And Jim''s dad is reliable as ever, doling out advice no one wants to hear.', NULL, NULL, 5.1984, 6.2, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
