INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5002, 584, 'tt0322259', NULL, '2 Fast 2 Furious', '2 Fast 2 Furious', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/6nDZExrDKIXvSAghsFKVFRVJuSf.jpg', 'https://image.tmdb.org/t/p/original/90ooE5SbUEO0OVJHewNO7pgySb6.jpg', 'It''s a major double-cross when former police officer Brian O''Conner teams up with his ex-con buddy Roman Pearce to transport a shipment of "dirty" money for shady Miami-based import-export dealer Carter Verone. But the guys are actually working with undercover agent Monica Fuentes to bring Verone down.', NULL, NULL, 1.3215, 6.523, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
