INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5006, 9471, 'tt0305357', NULL, 'Charlie''s Angels: Full Throttle', 'Charlie''s Angels: Full Throttle', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/n4cdJ0Wqxb7C0HmZbcaC4eYnkIf.jpg', 'https://image.tmdb.org/t/p/original/rS3QJdsCPyhhQ0mJEr8VirNmOMm.jpg', 'The Angels are charged with finding a pair of missing rings that are encoded with the personal information of members of the Witness Protection Program. As informants are killed, the ladies target a rogue agent who might be responsible.', NULL, NULL, 5.1535, 5.49, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
