INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5008, 15028, 'tt0157472', NULL, 'Clockstoppers', 'Clockstoppers', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/6XZJ58gStdLZV8uJyTRcA5bGNyi.jpg', 'https://image.tmdb.org/t/p/original/ygys5z5itmGGbSp2G003A6crCyO.jpg', 'Until now, Zak Gibbs'' greatest challenge has been to find a way to buy a car. But when he discovers an odd wristwatch amidst his father''s various inventions and slips it on -- something very strange happens. The world around him seems to come to a stop, everything and everybody frozen in time. Zak quickly learns how to manipulate the device and he and his quick-witted and beautiful new friend, Francesca, start to have some real fun.', NULL, NULL, 1.5989, 5.3, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5009, 10923, 'tt0313911', NULL, 'Agent Cody Banks', 'Agent Cody Banks', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/fhK0mqqirPsckxkNisvi32A4lf6.jpg', 'https://image.tmdb.org/t/p/original/5daWhr7xQwpdoRhoXnAOHWj2zhW.jpg', 'Recruited by the U.S. government to be a special agent, nerdy teenager Cody Banks must get closer to cute classmate Natalie in order to learn about an evil plan hatched by her father. But despite the agent persona, Cody struggles with teen angst.', NULL, NULL, 2.5287, 5.542, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5010, 19033, 'tt0460925', NULL, 'The Sasquatch Gang', 'The Sasquatch Gang', 'movie', 2006, 'https://image.tmdb.org/t/p/w500/f7Vnrik2tsozzG1DRfgIBmJvUCx.jpg', 'https://image.tmdb.org/t/p/original/xTaj3tVozMfcCrrndYVPic91bWr.jpg', 'Young fantasy and science fiction aficionado Gavin Gore and his friends stumble onto some huge footprints in the woods. A local cop, reporter, and a renowned Sasquatch authority investigate, while two of Gavin''s dim-witted neighbors hatch a scheme to profit from the situation.', NULL, NULL, 1.1102, 5.889, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5011, 11452, 'tt0283111', NULL, 'National Lampoon''s Van Wilder', 'National Lampoon''s Van Wilder', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/4IvM4qnzlo62oLmS54FtyRt54ze.jpg', 'https://image.tmdb.org/t/p/original/7CAEkkp07JBPHGIxmagu181f4CP.jpg', 'Van Wilder has been attending college for far too many years and is scared to graduate, but Van’s father eventually realizes what is going on. When he stops paying his son''s tuition fees, Van must come up with the money if he wants to stay in college, so he and his friends come up with a great fund-raising idea – throwing parties. However, when the college magazine finds out and reporter Gwen is sent to do a story on Van Wilder, things get a little complicated.', NULL, NULL, 2.6574, 6.033, 0, 1.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
