INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (5024, NULL, NULL, 1022, 'The Legend of Zelda', 'The Legend of Zelda', 'game', 1986, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uii.jpg', NULL, 'The Legend of Zelda is the first title in the Zelda series, it has marked the history of video games particularly for it''s game mechanics and universe. The player controls Link and must make his way through the forests, graveyards, plains and deserts of the Otherworld to find the secret entrances to the eight dungeons and try to restore the broken Triforce. Among the game''s mechanics, it was the first time we saw a continuous world that could be freely explored, power-ups that permanently enhanced the main character''s abilities and a battery save feature that allowed players to keep their progress instead of having to start over. The gameplay balanced action sequences with discovery, secrets and exploration.', 'https://www.igdb.com/games/the-legend-of-zelda', '["Family Computer Disk System", "Nintendo 3DS", "Wii", "Family Computer", "Wii U", "Nintendo Entertainment System"]', NULL, NULL, 0, 11.0, '2026-07-21 03:32:24', '2026-07-21 03:32:24');
