UPDATE "recommendations" SET "tmdb_id"=201085, "imdb_id"='tt2554274', "igdb_id"=NULL, "title"='Crimson Peak', "original_title"='Crimson Peak', "media_type"='movie', "release_year"=2015, "poster_url"='https://image.tmdb.org/t/p/w500/f9TOb5anVwZeSbYjU1qNxPk3KUk.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/nQQIUwEEqa6sjPvnqcGbjJxbdit.jpg', "overview"='In the aftermath of a family tragedy, an aspiring author is torn between love for her childhood friend and the temptation of a mysterious outsider. Trying to escape the ghosts of her past, she is swept away to a house that breathes, bleeds… and remembers.', "external_url"=NULL, "platforms"=NULL, "popularity"=3.8693, "vote_average"=6.662, "is_ambiguous"=0, "evidence_score"=2.83014285714285698e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=4;
UPDATE "recommendations" SET "tmdb_id"=120, "imdb_id"='tt0120737', "igdb_id"=NULL, "title"='The Lord of the Rings: The Fellowship of the Ring', "original_title"='The Lord of the Rings: The Fellowship of the Ring', "media_type"='movie', "release_year"=2001, "poster_url"='https://image.tmdb.org/t/p/w500/6oom5QYQ2yQTMJIbnvbkBL9cHo6.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/mWDdRXTivGE7aaY2vo1Ie0PfCX5.jpg', "overview"='Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.', "external_url"=NULL, "platforms"=NULL, "popularity"=26.6478, "vote_average"=8.438, "is_ambiguous"=0, "evidence_score"=34.4225, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=5;
UPDATE "recommendations" SET "tmdb_id"=9016, "imdb_id"='tt0133240', "igdb_id"=NULL, "title"='Treasure Planet', "original_title"='Treasure Planet', "media_type"='movie', "release_year"=2002, "poster_url"='https://image.tmdb.org/t/p/w500/kNhZkR3UNbXfvESQo7mJpOi4tGd.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/f2opsSUSiMdEp6AiY2sbC8QPd8S.jpg', "overview"='When space galleon cabin boy Jim Hawkins discovers a map to an intergalactic "loot of a thousand worlds," a cyborg cook named John Silver teaches him to battle supernovas and space storms on their journey to find treasure.', "external_url"=NULL, "platforms"=NULL, "popularity"=6.59, "vote_average"=7.575, "is_ambiguous"=0, "evidence_score"=11.004, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=11;
UPDATE "recommendations" SET "tmdb_id"=117488, "imdb_id"='tt11041332', "igdb_id"=NULL, "title"='Yellowjackets', "original_title"='Yellowjackets', "media_type"='tv', "release_year"=2021, "poster_url"='https://image.tmdb.org/t/p/w500/xRnGrn7Z7SC0KIBodocoU1QgDZF.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/ibFWJDWS8cTO6s2vZVd2uKDm8p.jpg', "overview"='This equal parts survival epic, psychological horror story and coming-of-age drama tells the saga of a team of wildly talented high school girls soccer players who become the (un)lucky survivors of a plane crash deep in the remote northern wilderness. The series chronicles their descent from a complicated but thriving team to savage clans, while also tracking the lives they’ve attempted to piece back together nearly 25 years later.', "external_url"=NULL, "platforms"=NULL, "popularity"=15.3211, "vote_average"=7.445, "is_ambiguous"=0, "evidence_score"=1.30042857142857144e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=14;
