UPDATE "recommendations" SET "tmdb_id"=13597, "imdb_id"='tt0091369', "igdb_id"=NULL, "title"='Labyrinth', "original_title"='Labyrinth', "media_type"='movie', "release_year"=1986, "poster_url"='https://image.tmdb.org/t/p/w500/pejayhTVBEL4w8YKSfrhOjjWVlH.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/mGkleIuPO2flRyvP8yBcUykSQsp.jpg', "overview"='Frustrated with babysitting on yet another weekend night, Sarah, a teenager with an active imagination, summons the Goblins to take her baby stepbrother away. When little Toby actually disappears, Sarah must follow him into a fantastical world to rescue him from the Goblin King. Guarding his castle is the labyrinth itself, a twisted maze of deception, populated with outrageous characters and unknown dangers.', "external_url"=NULL, "platforms"=NULL, "popularity"=5.4798, "vote_average"=7.29, "is_ambiguous"=0, "evidence_score"=1.22928571428571427e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=23;
