UPDATE "recommendations" SET "tmdb_id"=30959, "imdb_id"='tt0058279', "igdb_id"=NULL, "title"='Kwaidan', "original_title"='怪談', "media_type"='movie', "release_year"=1965, "poster_url"='https://image.tmdb.org/t/p/w500/t9UMfViYl47SdZZatKQ1JKjjCgs.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/9GAU0z2wVA8M2D2w36CaloWYYgv.jpg', "overview"='Taking its title from an archaic Japanese word meaning "ghost story," this anthology adapts four folk tales. A penniless samurai marries for money with tragic results. A man stranded in a blizzard is saved by Yuki the Snow Maiden, but his rescue comes at a cost. Blind musician Hoichi is forced to perform for an audience of ghosts. An author relates the story of a samurai who sees another warrior''s reflection in his teacup.', "external_url"=NULL, "platforms"=NULL, "popularity"=2.1889, "vote_average"=7.727, "is_ambiguous"=0, "evidence_score"=18.415, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=565;
UPDATE "recommendations" SET "tmdb_id"=2291, "imdb_id"='tt0099871', "igdb_id"=NULL, "title"='Jacob''s Ladder', "original_title"='Jacob''s Ladder', "media_type"='movie', "release_year"=1990, "poster_url"='https://image.tmdb.org/t/p/w500/ufLcHIi1aXjjH8MediAMvnwDsVI.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/oubk1SEFtg3Q8eOncFvGQVa6OoP.jpg', "overview"='After returning home from the Vietnam War, veteran Jacob Singer struggles to maintain his sanity. Plagued by hallucinations and flashbacks, Singer rapidly falls apart as the world and people around him morph and twist into disturbing images. His girlfriend, Jezzie, and ex-wife, Sarah, try to help, but to little avail. Even Singer''s chiropractor friend, Louis, fails to reach him as he descends into madness.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.0585, "vote_average"=7.368, "is_ambiguous"=0, "evidence_score"=2.34550000000000018e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=568;
