UPDATE "recommendations" SET "tmdb_id"=588, "imdb_id"='tt0384537', "igdb_id"=NULL, "title"='Silent Hill', "original_title"='Silent Hill', "media_type"='movie', "release_year"=2006, "poster_url"='https://image.tmdb.org/t/p/w500/r0bEDWO2w4a43K2xTNSF284qOsc.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/48TM0HjZSRjIr4QMuDTsMWcz7gX.jpg', "overview"='Rose, a desperate mother, takes her adopted daughter, Sharon, to the town of Silent Hill in an attempt to cure her of her ailment. After a violent car crash, Sharon disappears, and Rose embarks on a horrific journey to get her back and begins to uncover the truth behind the apocalyptic disaster that burned the town 30 years earlier.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.8277, "vote_average"=6.6, "is_ambiguous"=0, "evidence_score"=1.65466666666666668e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=573;
UPDATE "recommendations" SET "tmdb_id"=565, "imdb_id"='tt0298130', "igdb_id"=NULL, "title"='The Ring', "original_title"='The Ring', "media_type"='movie', "release_year"=2002, "poster_url"='https://image.tmdb.org/t/p/w500/AeRpUynJKDpJveklBJipOYrVxCS.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/6tuNQ16hC4Qp7wjTweKzUnnLBkI.jpg', "overview"='Journalist Rachel Keller investigates a strange videotape that may be behind the untimely deaths of four teenagers. There is an urban legend about this tape: the viewer will die seven days after watching it. Rachel tracks down the video... and watches it. Now she has just seven days to unravel the mystery of the Ring in order to save herself and her son.', "external_url"=NULL, "platforms"=NULL, "popularity"=6.7511, "vote_average"=6.707, "is_ambiguous"=0, "evidence_score"=1.89908333333333345e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=574;
