UPDATE "recommendations" SET "tmdb_id"=420818, "imdb_id"='tt6105098', "igdb_id"=NULL, "title"='The Lion King', "original_title"='The Lion King', "media_type"='movie', "release_year"=2019, "poster_url"='https://image.tmdb.org/t/p/w500/dzBtMocZuJbjLOXvrl4zGYigDzh.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/1TUg5pO1VZ4B0Q1amk3OlXvlpXV.jpg', "overview"='Simba idolizes his father, King Mufasa, and takes to heart his own royal destiny. But not everyone in the kingdom celebrates the new cub''s arrival. Scar, Mufasa''s brother—and former heir to the throne—has plans of his own. The battle for Pride Rock is ravaged with betrayal, tragedy and drama, ultimately resulting in Simba''s exile. With help from a curious pair of newfound friends, Simba will have to figure out how to grow up and take back what is rightfully his.', "external_url"=NULL, "platforms"=NULL, "popularity"=12.0387, "vote_average"=7.096, "is_ambiguous"=0, "evidence_score"=1.23014285714285716e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=725;
