UPDATE "recommendations" SET "tmdb_id"=386948, "imdb_id"='tt1623202', "igdb_id"=NULL, "title"='Beautiful Brazil', "original_title"='Beautiful Brazil', "media_type"='movie', "release_year"=1952, "poster_url"=NULL, "backdrop_url"=NULL, "overview"='We start in Rio de Janeiro, with the statue of Cristo Redentor on Mount Corcovado, the avenue along the beach, the beauty of an historic city, and the landmark, Sugarloaf. Brazil''s 47 million people celebrate racial diversity. From the Copacabana, we travel 40 miles to a resort, Quitandinha, where President Truman spoke. Then it''s on to Sao Paulo, a modern, industrial city, and finally to the spectacular waterfalls of Iguazu on the border between Brazil and Argentina.', "external_url"=NULL, "platforms"=NULL, "popularity"=0.1446, "vote_average"=7.0, "is_ambiguous"=0, "evidence_score"=1.4725999999999999e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=1099;
