UPDATE "recommendations" SET "tmdb_id"=14019, "imdb_id"='tt0812243', "igdb_id"=NULL, "title"='Ex Drummer', "original_title"='Ex Drummer', "media_type"='movie', "release_year"=2007, "poster_url"='https://image.tmdb.org/t/p/w500/7VxXp2h9UtJP6XbeuQGqqbQzoE1.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/mIYSIgQjTU0Y7e1yZ08E588A8av.jpg', "overview"='Three musicians form a band. But they''re not just any musicians: each has a disability that makes them particularly unsuitable for their instrument. The guitarist is deaf, the singer is tone deaf, and the bassist has a stiff arm. They lack a drummer, and to respect the group''s uniqueness, they turn to a famous writer who has never played the drums. He accepts, but begins a manipulation that will wreak further havoc on the already largely dysfunctional band.', "external_url"=NULL, "platforms"=NULL, "popularity"=0.7644, "vote_average"=6.818, "is_ambiguous"=0, "evidence_score"=7.005, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=1757;
