UPDATE "recommendations" SET "tmdb_id"=NULL, "imdb_id"=NULL, "igdb_id"=62, "title"='The Curse of Monkey Island', "original_title"='The Curse of Monkey Island', "media_type"='game', "release_year"=1997, "poster_url"='https://images.igdb.com/igdb/image/upload/t_cover_big/co30yu.jpg', "backdrop_url"=NULL, "overview"='The Curse of Monkey Island is the third installment in the Monkey Island adventure game series. Players control Guybrush Threepwood, a aspiring pirate, as he navigates the Caribbean to save his love Elaine from a curse that turned her into a golden statue. The game features hand-drawn cartoon graphics, voice acting, and the series'' trademark humor and puzzle-solving gameplay. Guybrush must outwit a cast of colorful characters, including the ghostly pirate LeChuck, while exploring various islands and engaging in pirate-themed challenges. The point-and-click interface allows players to interact with the environment, collect items, and solve puzzles to progress through the story. With its blend of comedy, swashbuckling adventure, and clever puzzles, The Curse of Monkey Island continues the series'' tradition of witty, engaging storytelling in a pirate-themed setting.', "external_url"='https://www.igdb.com/games/the-curse-of-monkey-island', "platforms"='["PC (Microsoft Windows)", "Mac"]', "popularity"=NULL, "vote_average"=NULL, "is_ambiguous"=0, "evidence_score"=7.004, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=1761;
