UPDATE "recommendations" SET "tmdb_id"=895, "imdb_id"='tt0060107', "igdb_id"=NULL, "title"='Andrei Rublev', "original_title"='Андрей Рублёв', "media_type"='movie', "release_year"=1966, "poster_url"='https://image.tmdb.org/t/p/w500/jUihkn16SwPPIjuOyo6orHWUep6.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/jqha8JCXm0aJ5SJ03Jd0JmGgWRs.jpg', "overview"='An expansive Russian drama, this film focuses on the life of revered religious icon painter Andrei Rublev. Drifting from place to place in a tumultuous era, the peace-seeking monk eventually gains a reputation for his art. But after Rublev witnesses a brutal battle and unintentionally becomes involved, he takes a vow of silence and spends time away from his work. As he begins to ease his troubled soul, he takes steps towards becoming a painter once again.', "external_url"=NULL, "platforms"=NULL, "popularity"=2.8641, "vote_average"=7.942, "is_ambiguous"=0, "evidence_score"=1.15025000000000012e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=1860;
