UPDATE "recommendations" SET "tmdb_id"=762361, "imdb_id"='tt13515090', "igdb_id"=NULL, "title"='Joyride', "original_title"='Joyride', "media_type"='movie', "release_year"=2022, "poster_url"='https://image.tmdb.org/t/p/w500/yJHwqLB5U3joO6sqVajDevGsRnz.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/qQfpXqKR6dewogmh3D6T0hFy3CE.jpg', "overview"='12-year-old Mully has lost his mother and discovers his debt-ridden father stealing the charity money they''ve raised in her name. Grabbing the cash, Mully steals a taxi and is shocked to find a woman, Joy, in the back seat with a baby. A straight-talking solicitor who didn''t expect to get pregnant, Joy is struggling with motherhood and planning to give her baby to a friend who will raise the child as her own. She joins Mully on a wild journey across Ireland, stealing cars, hitch-hiking, catching ferries and breaking police barricades.', "external_url"=NULL, "platforms"=NULL, "popularity"=0.7974, "vote_average"=5.846, "is_ambiguous"=0, "evidence_score"=11.025, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=1870;
