UPDATE "recommendations" SET "tmdb_id"=421, "imdb_id"='tt0362270', "igdb_id"=NULL, "title"='The Life Aquatic with Steve Zissou', "original_title"='The Life Aquatic with Steve Zissou', "media_type"='movie', "release_year"=2004, "poster_url"='https://image.tmdb.org/t/p/w500/qZoFLNBC78jzboWeDH6Ha0qavF2.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/7tWktnLQ81G8pHUkhuTebcTkcB3.jpg', "overview"='Renowned oceanographer Steve Zissou has sworn vengeance upon the rare shark that devoured a member of his crew. In addition to his regular team, he is joined on his boat by Ned, a man who believes Zissou to be his father, and Jane, a journalist pregnant by a married man. They travel the sea, all too often running into pirates and, perhaps more traumatically, various figures from Zissou''s past, including his estranged wife, Eleanor.', "external_url"=NULL, "platforms"=NULL, "popularity"=2.5824, "vote_average"=7.075, "is_ambiguous"=0, "evidence_score"=8.51, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=2491;
