UPDATE "recommendations" SET "tmdb_id"=66134, "imdb_id"='tt5014882', "igdb_id"=NULL, "title"='The Durrells', "original_title"='The Durrells', "media_type"='tv', "release_year"=2016, "poster_url"='https://image.tmdb.org/t/p/w500/sgZiuQ9PMeyHU7xMaIctwRu4SLa.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/lkb3NBvByVWBvr63wE4weHVFz4i.jpg', "overview"='In 1935, financially strapped widow Louisa Durrell, whose life has fallen apart, decides to move from England, with her four children (three sons, one daughter), to the island of Corfu, Greece. Once there, the family moves into a dilapidated old house that has no electricity and that is crumbling apart. But life on Corfu is cheap, it''s an earthly paradise, and the Durrells proceed to forge their new existence, with all its challenges, adventures, and forming relationships.', "external_url"=NULL, "platforms"=NULL, "popularity"=6.0975, "vote_average"=7.402, "is_ambiguous"=0, "evidence_score"=6.55, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=2518;
UPDATE "recommendations" SET "tmdb_id"=122906, "imdb_id"='tt2194499', "igdb_id"=NULL, "title"='About Time', "original_title"='About Time', "media_type"='movie', "release_year"=2013, "poster_url"='https://image.tmdb.org/t/p/w500/ls6zswrOZVhCXQBh96DlbnLBajM.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/einbto9qLXFx9QXxEHylaxDbKPx.jpg', "overview"='The night after another unsatisfactory New Year''s party, Tim''s father reveals to him that the men in their family have the ability to travel through time. They can''t change history, but they can change what happens and has happened in their own lives. Thus begins the start of a lesson in learning to appreciate life itself as it is, as it comes, and most importantly, the people living alongside us.', "external_url"=NULL, "platforms"=NULL, "popularity"=11.5749, "vote_average"=7.907, "is_ambiguous"=0, "evidence_score"=8.775, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=2522;
