UPDATE "recommendations" SET "tmdb_id"=62677, "imdb_id"='tt0210299', "igdb_id"=NULL, "title"='Songcatcher', "original_title"='Songcatcher', "media_type"='movie', "release_year"=2001, "poster_url"='https://image.tmdb.org/t/p/w500/qpUSLY5BPi42rqO097tNF8e53Qm.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/1ExirZYN7X0Vowg57XW71JQHtxo.jpg', "overview"='After being denied a promotion at the university where she teaches, Doctor Lily Penleric, a brilliant musicologist, impulsively visits her sister, who runs a struggling rural school in Appalachia. There she stumbles upon the discovery of her life - a treasure trove of ancient Scots-Irish ballads, songs that have been handed down from generation to generation, preserved intact by the seclusion of the mountains. With the goal of securing her promotion, Lily ventures into the most isolated areas of the mountains to collect the songs and finds herself increasingly enchanted.', "external_url"=NULL, "platforms"=NULL, "popularity"=0.6222, "vote_average"=6.205, "is_ambiguous"=0, "evidence_score"=6.525, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=2568;
UPDATE "recommendations" SET "tmdb_id"=82633, "imdb_id"='tt1212450', "igdb_id"=NULL, "title"='Lawless', "original_title"='Lawless', "media_type"='movie', "release_year"=2012, "poster_url"='https://image.tmdb.org/t/p/w500/Ahtzwts22ayviD3LEVslfL4nRWB.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/6zTqEmFWlmmPPY907qwvv9WQBUm.jpg', "overview"='In 1931, the Bondurant brothers of Franklin County, Virginia, run a multipurpose backwoods establishment that hides their true business — bootlegging. Middle brother Forrest is the brain of the operation; older Howard is the brawn, and younger Jack, the lookout. Though the local police have taken bribes and left the brothers alone, a violent war erupts when a sadistic lawman from Chicago arrives and tries to shut down the Bondurants operation.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.4913, "vote_average"=7.07, "is_ambiguous"=0, "evidence_score"=1.66955555555555541e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-21 03:32:24' WHERE "id"=2569;
