UPDATE "recommendations" SET "tmdb_id"=52001, "imdb_id"='tt1641975', "igdb_id"=NULL, "title"='Citadel', "original_title"='Citadel', "media_type"='movie', "release_year"=2012, "poster_url"='https://image.tmdb.org/t/p/w500/2NBxSwARcPi4wwpLH1wyFWKXeJo.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/qzpjvSQ1qADIf9mIICHNKt2W00D.jpg', "overview"='Chronically agoraphobic since the day his wife was murdered, Tommy Cowley finds himself terrorized by a gang of syringe-wielding feral children, who are intent on taking his baby daughter. Upon discovering the nightmarish truth surrounding these hooded children, he learns that to be free of his fears, he must finally face the demons of his past and enter the one place he fears the most - the abandoned tower block, known as the Citadel.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.3112, "vote_average"=5.351, "is_ambiguous"=0, "evidence_score"=9.0, "created_at"='2026-07-20 01:02:04', "updated_at"='2026-07-21 03:32:24' WHERE "id"=3421;
