UPDATE "recommendations" SET "tmdb_id"=974655, "imdb_id"='tt0222042', "igdb_id"=NULL, "title"='The Irony of Fate', "original_title"='The Irony of Fate', "media_type"='movie', "release_year"=1912, "poster_url"=NULL, "backdrop_url"=NULL, "overview"='Virginia Jameson, a girl of lovely disposition, is wooed by a man much older than herself whom she very much dislikes, but who stands very high in the favor of her parents. She might have married another man had not fate decreed otherwise. She meets and accidentally escapes the man she could have loved and would have married; she stooped to tie her shoe-strings, diverting her attention from him. Had their eyes met, both their lives would have been different. Leroy Farley, the man favored by her parents, prevails and she marries him. Her life is unhappy, notwithstanding his great riches and social prominence.', "external_url"=NULL, "platforms"=NULL, "popularity"=0.0999, "vote_average"=8.0, "is_ambiguous"=0, "evidence_score"=11.0, "created_at"='2026-07-20 01:02:04', "updated_at"='2026-07-21 03:32:24' WHERE "id"=3425;
