UPDATE "recommendations" SET "tmdb_id"=12620, "imdb_id"='tt0852713', "igdb_id"=NULL, "title"='The House Bunny', "original_title"='The House Bunny', "media_type"='movie', "release_year"=2008, "poster_url"='https://image.tmdb.org/t/p/w500/4oGGJ824vqIqDtyMvMuK44pDEmx.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/vz6iY1MtETWRtZMn379JYZGVCX1.jpg', "overview"='Shelley is living a carefree life until a rival gets her tossed out of the Playboy Mansion. With nowhere to go, fate delivers her to the sorority girls from Zeta Alpha Zeta. Unless they can sign a new pledge class, the seven socially clueless women will lose their house to the scheming girls of Phi Iota Mu. In order to accomplish their goal, they need Shelley to teach them the ways of makeup and men; at the same time, Shelley needs some of what the Zetas have - a sense of individuality. The combination leads all the girls to learn how to stop pretending and start being themselves.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.7939, "vote_average"=5.681, "is_ambiguous"=0, "evidence_score"=3.0, "created_at"='2026-07-20 01:02:04', "updated_at"='2026-07-21 03:32:24' WHERE "id"=3508;
